// Iniciar análisis cognitivo del cliente
const body = $input.first().json;

const sessionId = body.session_id || crypto.randomUUID();
const nombre = body.nombre || 'Cliente';
const telefono = body.telefono || '';
const servicioInteres = body.servicio || 'soporte';
const mensajeInicial = body.mensaje || '';
const historial = body.historial || [];
const imagen = body.imagen || null;
const tipoImagen = body.tipo_imagen || 'image/jpeg';

// Mapa de servicios con palabras clave
const servicios = {
  soporte: { nombre: 'Soporte Técnico', keywords: ['pc', 'computadora', 'lenta', 'error', 'windows', 'blue', 'no enciende', 'internet', 'red', 'wifi'] },
  infra: { nombre: 'Infraestructura', keywords: ['servidor', 'data center', 'red', 'rack', 'backup', 'energia', 'ups', 'nube', 'azure', 'aws'] },
  cyber: { nombre: 'Ciberseguridad', keywords: ['seguro', 'virus', 'hack', 'ransomware', 'proteger', 'firewall', 'vpn', 'ataque', 'datos', 'robo'] },
  ia: { nombre: 'Automatización IA', keywords: ['automatizar', 'ia', 'ai', 'robot', 'proceso', 'chatbot', 'agente', 'flujo', 'optimizar'] }
};

// Determinar servicio basado en keywords
let servicioDetectado = servicioInteres;
const mensajeLower = (mensajeInicial + ' ' + historial.join(' ')).toLowerCase();

for (const [key, data] of Object.entries(servicios)) {
  if (data.keywords.some(k => mensajeLower.includes(k))) {
    servicioDetectado = key;
    break;
  }
}

return {
  json: {
    sessionId,
    nombre,
    telefono,
    servicio: servicioDetectado,
    servicioNombre: servicios[servicioDetectado].nombre,
    mensajeInicial,
    historial,
    imagen,
    tipoImagen,
    contactoWA: telefono.replace(/\D/g, ''),
    fase: 'diagnostico', // diagnostico | agendamiento | confirmado
    timestamp: new Date().toISOString()
  }
};

// Procesar respuesta de la IA y tomar decisión
const input = $input.first().json;
const datos = $('Iniciar Sesión Cognitiva').first().json;

let respuesta = {
  tipo: 'preguntar',
  preguntas: [],
  diagnostico: null,
  accion: 'preguntar',
  mensaje: ''
};

try {
  if (input.candidates && input.candidates[0]?.content?.parts[0]?.text) {
    const texto = input.candidates[0].content.parts[0].text;

    // Intentar parsear JSON de la respuesta
    const jsonMatch = texto.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      respuesta = JSON.parse(jsonMatch[0]);
    } else {
      // Si no es JSON, crear respuesta de preguntas
      respuesta.mensaje = texto;
      respuesta.preguntas = texto.split('?').filter(p => p.trim()).slice(0, 3).map(p => p.trim() + '?');
    }
  }
} catch (e) {
  respuesta.mensaje = 'He recibido tu mensaje. Para darte el mejor diagnóstico, necesito hacerte algunas preguntas.';
  respuesta.preguntas = ['¿Cuándo began el problema?', '¿Qué exacte está pasando?', '¿Ya intentaste algo?'];
}

// Determinar siguiente paso
const debeAgendar = respuesta.accion === 'agendar' || (respuesta.diagnostico && respuesta.diagnostico.duracion);

return {
  json: {
    ...datos,
    analisis: respuesta,
    mensajeIA: respuesta.mensaje || respuesta.preguntas.join('\n'),
    preguntas: respuesta.preguntas,
    diagnostico: respuesta.diagnostico,
    listoParaAgendar: debeAgendar,
    fase: debeAgendar ? 'agendamiento' : 'diagnostico'
  }
};

